const body = $('Webhook').first().json.body || {};
const action = body.action || 'ingest';

if (action === 'list') {
  return [{ json: { action: 'list', ndaa: null } }];
}

const ndaa = {
  bill: 'P.L. 119-60 - National Defense Authorization Act for Fiscal Year 2026',
  total_authorized: '$890.6B',
  provisions: [
    { section: 'Sec 804', title: 'Multiyear Munitions Procurement', impact: 'Expands industrial base capacity', category: 'acquisition' },
    { section: 'SPEED Act', title: 'Acquisition Reform / Streamlined Procurement', impact: 'Faster awards - benefits agile integrators like GDA', category: 'acquisition' },
    { section: 'Golden Dome', title: '$25B initial appropriation (P.L. 119-21)', impact: 'MDA SHIELD IDIQ - EIS position HQ085925RE001', category: 'strategic' },
    { section: 'SAFER SKIES', title: 'Counter-UAS authorities', impact: 'CUAS requirements flowing to SOCOM, NORTHCOM', category: 'capability' },
    { section: 'PDI', title: 'Pacific Deterrence Initiative full funding', impact: 'INDOPACOM C5ISR/IT support expanding', category: 'geographic' },
    { section: 'Cyber', title: 'CYBERCOM and cyber workforce provisions', impact: 'Cyber SETA/training requirements expanding', category: 'capability' },
    { section: 'AI/Data', title: 'AI and data management requirements', impact: 'DoD AI adoption mandates = consulting opps', category: 'technology' },
    { section: 'SB Reform', title: 'Small business acquisition streamlining', impact: '8(a)/SB set-asides benefit EIS/PD/Riverstone', category: 'set-aside' },
  ],
  far_sections: [
    { part: 'FAR 16.5', title: 'Indefinite-Delivery Contracts', impact: 'IDIQ on-ramp rules - 5-year open season requirement', category: 'idiq' },
    { part: 'FAR 19', title: 'Small Business Programs', impact: 'Set-aside thresholds, 8(a), SDVOSB, HUBZone', category: 'set-aside' },
    { part: 'DFARS 252.204-7012', title: 'Safeguarding CDI', impact: 'CMMC compliance for all DoD contracts', category: 'compliance' },
  ]
};
return [{ json: { action: 'ingest', ndaa } }];

const action = $('Build NDAA Data').first().json.action || 'ingest';
const ndaa = $('Build NDAA Data').first().json.ndaa || {};

if (action === 'list') {
  const rows = $input.all().map(i => i.json).filter(r => r && r.section);
  return [{ json: {
    status: 'ok',
    key_provisions_for_gda: rows,
    ndaa_summary: { provisions: rows },
    count: rows.length
  }}];
}

return [{ json: {
  status: 'ndaa_far_ingested',
  bill: ndaa.bill,
  total_authorized: ndaa.total_authorized,
  provisions_stored: (ndaa.provisions||[]).length,
  far_sections_stored: (ndaa.far_sections||[]).length,
  total_records: (ndaa.provisions||[]).length + (ndaa.far_sections||[]).length,
  timestamp: new Date().toISOString()
}}];
